'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { usePathname } from 'next/navigation';
import { FaStream, FaTimes } from 'react-icons/fa';

const navLinks = [
  { label: 'Home', href: '/' },
  { label: 'About', href: '/about' },
  { label: 'Service', href: '/ewaste' },
  { label: 'Contact', href: '/contact' },
];

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const pathname = usePathname();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 100);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  // Close mobile menu when clicking outside or on route change
  useEffect(() => {
    setIsOpen(false);
  }, [pathname]);

  // Prevent body scroll when mobile menu is open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isOpen]);

  return (
    <header 
      className={`header_wrapper fixed top-0 left-0 w-full z-50 transition-all duration-300 ${
        scrolled ? 'bg-white shadow-md' : 'bg-transparent'
      }`}
      role="banner"
    >
      <nav className="navbar navbar-expand-lg py-3 md:py-4" role="navigation" aria-label="Main navigation">
        <div className="container mx-auto flex justify-between items-center px-4 max-w-7xl">
          <Link 
            href="/" 
            className="navbar-brand flex items-center focus:outline-none focus:ring-2 focus:ring-secondary-color focus:ring-offset-2 rounded"
            aria-label="Austic Scrap Home"
          >
            <div className="brand-content flex items-center gap-2 md:gap-3">
              <Image
                src="/images/starbuck logo.png"
                alt="Austic Scrap Logo"
                width={158}
                height={158}
                className="img-fluid max-h-[40px] sm:max-h-[50px] md:max-h-[60px] w-auto h-auto object-contain"
                priority
              />
              <p 
                className="brand-text text-xl sm:text-2xl md:text-3xl lg:text-[34px] font-semibold whitespace-nowrap"
                style={{
                  background: 'linear-gradient(190deg, #0e510e, #00FB82, #127749)',
                  WebkitBackgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                  backgroundClip: 'text',
                }}
              >
                AUSTIC SCRAP
              </p>
            </div>
          </Link>

          {/* Mobile Toggler */}
          <button
            className="navbar-toggler lg:hidden border-0 shadow-none text-text-black-dark text-2xl p-2 focus:outline-none focus:ring-2 focus:ring-secondary-color focus:ring-offset-2 rounded transition-colors hover:bg-gray-100"
            onClick={() => setIsOpen(!isOpen)}
            aria-label={isOpen ? 'Close navigation menu' : 'Open navigation menu'}
            aria-expanded={isOpen}
            aria-controls="navbarNav"
          >
            {isOpen ? <FaTimes aria-hidden="true" /> : <FaStream aria-hidden="true" />}
          </button>

          {/* Desktop Menu */}
          <div className="hidden lg:flex justify-end" id="navbarNav">
            <ul className="navbar-nav menu-navbar-nav flex space-x-6 xl:space-x-8" role="menubar">
              {navLinks.map((link) => {
                const isActive = pathname === link.href;
                return (
                  <li key={link.label} className="nav-item" role="none">
                    <Link
                      href={link.href}
                      className={`nav-link text-base xl:text-lg font-normal transition-colors duration-300 px-2 py-1 rounded focus:outline-none focus:ring-2 focus:ring-secondary-color focus:ring-offset-2 ${
                        isActive 
                          ? 'text-text-secondary font-semibold' 
                          : 'text-text-primary hover:text-text-secondary'
                      }`}
                      role="menuitem"
                      aria-current={isActive ? 'page' : undefined}
                    >
                      {link.label}
                    </Link>
                  </li>
                );
              })}
            </ul>
          </div>

          {/* Mobile Menu Overlay */}
          <div
            className={`fixed inset-0 bg-black bg-opacity-50 transition-opacity duration-300 lg:hidden ${
              isOpen ? 'opacity-100 z-40' : 'opacity-0 -z-10 pointer-events-none'
            }`}
            onClick={() => setIsOpen(false)}
            aria-hidden={!isOpen}
          />
          <div
            className={`fixed top-0 right-0 h-full w-[85%] max-w-sm bg-bg-light-green p-4 transition-transform duration-300 ease-in-out lg:hidden z-50 ${
              isOpen ? 'translate-x-0' : 'translate-x-full'
            }`}
            id="mobile-menu"
            role="dialog"
            aria-modal="true"
            aria-labelledby="mobile-menu-title"
          >
            <div className="flex justify-between items-center mb-8 pt-2">
              <h2 id="mobile-menu-title" className="text-color-wheat text-xl font-semibold sr-only">
                Navigation Menu
              </h2>
              <button
                className="text-color-wheat text-2xl p-2 focus:outline-none focus:ring-2 focus:ring-color-wheat focus:ring-offset-2 focus:ring-offset-bg-light-green rounded transition-colors hover:bg-opacity-20 hover:bg-black"
                onClick={() => setIsOpen(false)}
                aria-label="Close navigation menu"
              >
                <FaTimes aria-hidden="true" />
              </button>
            </div>
            <ul className="flex flex-col space-y-4" role="menubar">
              {navLinks.map((link) => {
                const isActive = pathname === link.href;
                return (
                  <li key={link.label} className="nav-item" role="none">
                    <Link
                      href={link.href}
                      className={`nav-link text-lg text-color-wheat py-3 px-4 rounded transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-color-wheat focus:ring-offset-2 focus:ring-offset-bg-light-green ${
                        isActive 
                          ? 'font-bold bg-black bg-opacity-20' 
                          : 'hover:bg-black hover:bg-opacity-10 hover:underline'
                      }`}
                      role="menuitem"
                      aria-current={isActive ? 'page' : undefined}
                      onClick={() => setIsOpen(false)}
                    >
                      {link.label}
                    </Link>
                  </li>
                );
              })}
            </ul>
          </div>
        </div>
      </nav>
    </header>
  );
};

export default Navbar;